function rearrangeBarcodes(barcodes) {
    const count = new Map();
    for (const barcode of barcodes) {
        count.set(barcode, (count.get(barcode) || 0) + 1);
    }

    const pq = Array.from(count.entries());
    pq.sort((a, b) => b[1] - a[1]);

    let index = 0;
    while (pq.length) {
        const curr = pq.shift();
        while (curr[1] > 0) {
            barcodes[index] = curr[0];
            curr[1]--;
            index += 2;
            if (index >= barcodes.length) {
                index = 1;
            }
        }
    }
    return barcodes;
}
